import React from 'react';
import { BrowserRouter, Switch, Route } from 'react-router-dom';

// Existing pages
import HomePage from './pages/acceuil/HomePage';
import AuthPage from './pages/auth/AuthPage';
import LogementsPage from './pages/logements/LogementsPage';

// Voyageur pages
import LogementDetailPage from './pages/voyageur/LogementDetailPage';
import ProfilPage from './pages/voyageur/ProfilPage';
import MesReservationsPage from './pages/voyageur/MesReservationsPage';

// Hôte pages
import HoteDashboardPage from './pages/hote/HoteDashboardPage';
import AjouterLogementPage from './pages/hote/AjouterLogementPage';
import ModifierLogementPage from './pages/hote/ModifierLogementPage';
import MesLogementsPage from './pages/hote/MesLogementsPage';
import ReservationsRecuesPage from './pages/hote/ReservationsRecuesPage';

// Admin pages
import AdminDashboardPage from './pages/admin/AdminDashboardPage';
import GestionUtilisateursPage from './pages/admin/GestionUtilisateursPage';
import GestionLogementsPage from './pages/admin/GestionLogementsPage';
import ValidationLogementsPage from './pages/admin/ValidationLogementsPage';
import StatistiquesPage from './pages/admin/StatistiquesPage';

function App() {
  return (
    <BrowserRouter>
      <Switch>
        {/* ── Voyageur ── */}
        <Route path="/" component={HomePage} exact />
        <Route path="/connexion" render={(props) => <AuthPage {...props} defaultTab="connexion" />} />
        <Route path="/inscription" render={(props) => <AuthPage {...props} defaultTab="inscription" />} />
        <Route path="/logements" component={LogementsPage} exact />
        <Route path="/logements/:id" component={LogementDetailPage} />
        <Route path="/profil" component={ProfilPage} />
        <Route path="/mes-reservations" component={MesReservationsPage} />

        {/* ── Hôte ── */}
        <Route path="/hote/dashboard" component={HoteDashboardPage} />
        <Route path="/hote/ajouter" component={AjouterLogementPage} />
        <Route path="/hote/modifier/:id" component={ModifierLogementPage} />
        <Route path="/hote/mes-logements" component={MesLogementsPage} />
        <Route path="/hote/reservations" component={ReservationsRecuesPage} />

        {/* ── Admin ── */}
        <Route path="/admin/dashboard" component={AdminDashboardPage} />
        <Route path="/admin/utilisateurs" component={GestionUtilisateursPage} />
        <Route path="/admin/logements" component={GestionLogementsPage} />
        <Route path="/admin/validation" component={ValidationLogementsPage} />
        <Route path="/admin/statistiques" component={StatistiquesPage} />
      </Switch>
    </BrowserRouter>
  );
}

export default App;
