import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import {
  Star, MapPin, Waves, ChefHat, Wind, Wifi, Car,
  BedDouble, Dumbbell, CalendarDays, Users, Check,
} from 'lucide-react';
import Navbar from '../../components/Navbar';
import Footer from '../../components/Footer';
import { villaDetails } from '../../data/adminMockData';
import styles from './LogementDetailPage.module.css';

const ICON_MAP: Record<string, React.ReactNode> = {
  Waves: <Waves size={18} />,
  ChefHat: <ChefHat size={18} />,
  Wind: <Wind size={18} />,
  Wifi: <Wifi size={18} />,
  Car: <Car size={18} />,
  BedDouble: <BedDouble size={18} />,
  Dumbbell: <Dumbbell size={18} />,
  Sunset: <Star size={18} />,
};

const LogementDetailPage = () => {
  const villa = villaDetails;
  const [activeImg, setActiveImg] = useState(0);
  const [dateArrivee, setDateArrivee] = useState('');
  const [dateDepart, setDateDepart] = useState('');
  const [voyageurs, setVoyageurs] = useState(2);

  return (
    <div className={styles.page}>
      <Navbar />

      <div className={styles.inner}>
        {/* Breadcrumb */}
        <div className={styles.breadcrumb}>
          <Link to="/" className={styles.breadLink}>Accueil</Link>
          <span className={styles.breadSep}>/</span>
          <Link to="/logements" className={styles.breadLink}>Logements</Link>
          <span className={styles.breadSep}>/</span>
          <span className={styles.breadCurrent}>{villa.name}</span>
        </div>

        {/* Title row */}
        <div className={styles.titleRow}>
          <div>
            <h1 className={styles.villaTitle}>{villa.name}</h1>
            <div className={styles.meta}>
              <span className={styles.ratingRow}>
                <Star size={14} fill="currentColor" className={styles.starIcon} />
                {villa.rating} <span className={styles.reviewCount}>({villa.reviewCount} avis)</span>
              </span>
              <span className={styles.metaDot}>·</span>
              <span className={styles.locationRow}>
                <MapPin size={13} />
                {villa.location}
              </span>
            </div>
          </div>
          <div className={styles.priceTag}>
            <span className={styles.priceAmount}>{villa.pricePerNight.toLocaleString('fr-FR')} FCFA</span>
            <span className={styles.priceUnit}> / nuit</span>
          </div>
        </div>

        {/* Gallery */}
        <div className={styles.gallery}>
          <div className={styles.mainImg}>
            <img src={villa.images[activeImg]} alt={villa.name} className={styles.mainImgEl} />
          </div>
          <div className={styles.thumbGrid}>
            {villa.images.map((img, i) => (
              <button
                key={i}
                onClick={() => setActiveImg(i)}
                className={`${styles.thumbBtn} ${i === activeImg ? styles.thumbBtnActive : ''}`}
              >
                <img src={img} alt={`Vue ${i + 1}`} className={styles.thumbImg} />
              </button>
            ))}
          </div>
        </div>

        {/* Body */}
        <div className={styles.body}>
          {/* Left: description + amenities */}
          <div className={styles.leftCol}>
            {/* Host */}
            <div className={styles.hostRow}>
              <img src={villa.host.avatar} alt={villa.host.name} className={styles.hostAvatar} />
              <div>
                <p className={styles.hostedBy}>Hébergement proposé par</p>
                <p className={styles.hostName}>{villa.host.name}</p>
                <p className={styles.hostSince}>Hôte depuis {villa.host.joinDate} · ★ {villa.host.rating}</p>
              </div>
            </div>

            <hr className={styles.sep} />

            {/* Description */}
            <h2 className={styles.sectionTitle}>À propos de cette villa</h2>
            <p className={styles.description}>{villa.description}</p>

            <hr className={styles.sep} />

            {/* Amenities */}
            <h2 className={styles.sectionTitle}>Équipements</h2>
            <div className={styles.amenitiesGrid}>
              {villa.amenities.map((a) => (
                <div key={a.label} className={styles.amenityItem}>
                  <span className={styles.amenityIcon}>{ICON_MAP[a.icon] ?? <Check size={18} />}</span>
                  <span className={styles.amenityLabel}>{a.label}</span>
                </div>
              ))}
            </div>
          </div>

          {/* Right: booking card */}
          <div className={styles.rightCol}>
            <div className={styles.bookingCard}>
              <p className={styles.bookingPrice}>
                <strong>{villa.pricePerNight.toLocaleString('fr-FR')} FCFA</strong>
                <span> / nuit</span>
              </p>

              <div className={styles.dateGrid}>
                <div className={styles.dateField}>
                  <label className={styles.dateLabel}>
                    <CalendarDays size={12} /> ARRIVÉE
                  </label>
                  <input
                    type="date"
                    className={styles.dateInput}
                    value={dateArrivee}
                    onChange={(e) => setDateArrivee(e.target.value)}
                  />
                </div>
                <div className={styles.dateField}>
                  <label className={styles.dateLabel}>
                    <CalendarDays size={12} /> DÉPART
                  </label>
                  <input
                    type="date"
                    className={styles.dateInput}
                    value={dateDepart}
                    onChange={(e) => setDateDepart(e.target.value)}
                  />
                </div>
              </div>

              <div className={styles.voyageursField}>
                <label className={styles.dateLabel}>
                  <Users size={12} /> VOYAGEURS
                </label>
                <div className={styles.counter}>
                  <button className={styles.counterBtn} onClick={() => setVoyageurs(Math.max(1, voyageurs - 1))}>−</button>
                  <span className={styles.counterVal}>{voyageurs}</span>
                  <button className={styles.counterBtn} onClick={() => setVoyageurs(voyageurs + 1)}>+</button>
                </div>
              </div>

              <button className={styles.reserveBtn}>Réserver maintenant</button>

              <div className={styles.bookingSummary}>
                <div className={styles.summaryRow}>
                  <span>{villa.pricePerNight.toLocaleString('fr-FR')} × 7 nuits</span>
                  <span>{(villa.pricePerNight * 7).toLocaleString('fr-FR')} FCFA</span>
                </div>
                <div className={styles.summaryRow}>
                  <span>Frais de service</span>
                  <span>150 000 FCFA</span>
                </div>
                <hr className={styles.sumSep} />
                <div className={`${styles.summaryRow} ${styles.summaryTotal}`}>
                  <span>Total</span>
                  <span>{(villa.pricePerNight * 7 + 150000).toLocaleString('fr-FR')} FCFA</span>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      <Footer />
    </div>
  );
};

export default LogementDetailPage;
