export interface Reservation {
  id: number;
  villaName: string;
  voyageur: string;
  avatar: string;
  location: string;
  dateArrivee: string;
  dateDepart: string;
  nuits: number;
  montant: string;
  status: 'confirmée' | 'en attente' | 'annulée';
  image: string;
}

export interface User {
  id: number;
  name: string;
  email: string;
  role: 'Voyageur' | 'Hôte' | 'Admin';
  status: 'actif' | 'inactif' | 'suspendu';
  joinDate: string;
  avatar: string;
  reservations: number;
}

export interface VillaHote {
  id: number;
  name: string;
  location: string;
  price: string;
  status: 'publié' | 'brouillon' | 'suspendu';
  image: string;
  reservations: number;
  rating: number;
}

export interface PendingLogement {
  id: number;
  name: string;
  hote: string;
  location: string;
  price: string;
  submittedDate: string;
  image: string;
  type: string;
}

export interface StatMonth {
  mois: string;
  reservations: number;
  revenus: number;
}

