import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { ArrowLeft, ChevronDown, Search } from 'lucide-react';
import Navbar from '../../components/Navbar';
import Footer from '../../components/Footer';
import { villas, poolImage, kitchenImage, heroVillaImage } from '../../data/mockData';
import styles from './LogementsPage.module.css';

const LOCATIONS = ['Dakar', 'Saly', 'Casamance', 'Thiès', 'Mbour', 'Saint-Louis'];
const RENT_TYPES = ['Par nuit', 'Par semaine', 'Par mois'];
const PRICE_RANGES = ['100k – 200k FCFA', '200k – 350k FCFA', '350k – 500k FCFA', '500k+'];

const LogementsPage = () => {
  const [location, setLocation] = useState('Dakar');
  const [rentType, setRentType] = useState('Par nuit');
  const [priceRange, setPriceRange] = useState('200k – 350k FCFA');
  const [showAll, setShowAll] = useState(false);

  const displayed = showAll ? villas : villas.slice(0, 6);

  return (
    <div className={styles.page}>
      <Navbar />

      {/* ---- HERO ---- */}
      <section
        className={styles.hero}
        style={{ backgroundImage: `url(${heroVillaImage})` }}
      >
        <div className={styles.heroOverlay} />
        <div className={styles.heroContent}>
          <Link to="/" className={styles.backLink}>
            <ArrowLeft size={14} />
            Retour
          </Link>
          <h1 className={styles.heroTitle}>Nos Villas d'Exception</h1>
          <p className={styles.heroSub}>Résidences de prestige pour des séjours inoubliables</p>
        </div>
      </section>

      {/* ---- SEARCH BAR ---- */}
      <section className={styles.searchSection}>
        <div className={styles.searchInner}>
          <p className={styles.searchHeading}>Trouvez votre villa idéale</p>
          <div className={styles.searchRow}>
            {/* Location */}
            <div className={styles.filterGroup}>
              <span className={styles.filterLabel}>Localisation</span>
              <div className={styles.selectWrapper}>
                <select
                  className={styles.select}
                  value={location}
                  onChange={(e) => setLocation(e.target.value)}
                >
                  {LOCATIONS.map((l) => (
                    <option key={l} value={l}>{l}</option>
                  ))}
                </select>
                <ChevronDown size={14} className={styles.selectIcon} />
              </div>
            </div>

            {/* Rent type */}
            <div className={styles.filterGroup}>
              <span className={styles.filterLabel}>Location</span>
              <div className={styles.selectWrapper}>
                <select
                  className={styles.select}
                  value={rentType}
                  onChange={(e) => setRentType(e.target.value)}
                >
                  {RENT_TYPES.map((r) => (
                    <option key={r} value={r}>{r}</option>
                  ))}
                </select>
                <ChevronDown size={14} className={styles.selectIcon} />
              </div>
            </div>

            {/* Price range */}
            <div className={styles.filterGroup}>
              <span className={styles.filterLabel}>Budget</span>
              <div className={styles.selectWrapper}>
                <select
                  className={styles.select}
                  value={priceRange}
                  onChange={(e) => setPriceRange(e.target.value)}
                >
                  {PRICE_RANGES.map((p) => (
                    <option key={p} value={p}>{p}</option>
                  ))}
                </select>
                <ChevronDown size={14} className={styles.selectIcon} />
              </div>
            </div>

            {/* CTA */}
            <button className={styles.searchBtn}>
              <Search size={15} />
              Rechercher
            </button>
          </div>
        </div>
      </section>

      {/* ---- PROPERTY GRID ---- */}
      <section className={styles.gridSection}>
        <div className={styles.gridInner}>
          <div className={styles.propertyGrid}>
            {displayed.map((villa) => (
              <div key={villa.id} className={styles.propertyCard}>
                <div className={styles.propertyImageWrapper}>
                  <img src={villa.image} alt={`Villa ${villa.location}`} className={styles.propertyImage} />
                  <div className={styles.propertyOverlay} />
                </div>
                <div className={styles.propertyInfo}>
                  <span className={styles.propertyLocation}>{villa.location}</span>
                  <span className={styles.propertyPrice}>{villa.price}</span>
                </div>
              </div>
            ))}
          </div>

          {!showAll && (
            <div className={styles.showMoreWrapper}>
              <button className={styles.showMoreBtn} onClick={() => setShowAll(true)}>
                Voir plus
              </button>
            </div>
          )}
        </div>
      </section>

      {/* ---- INFO SECTION ---- */}
      <section className={styles.infoSection}>
        <div className={styles.infoInner}>
          <h2 className={styles.infoTitle}>Informations sur nos villas</h2>

          {/* Pool row */}
          <div className={styles.infoRow}>
            <div className={styles.infoImageWrapper}>
              <img src={poolImage} alt="Piscine de la villa" className={styles.infoImage} />
            </div>
            <div className={styles.infoContent}>
              <h3 className={styles.infoFeatureTitle}>Piscine Privée</h3>
              <table className={styles.specTable}>
                <thead>
                  <tr>
                    <th>Longueur</th>
                    <th>Largeur</th>
                    <th>Profondeur</th>
                  </tr>
                </thead>
                <tbody>
                  <tr>
                    <td>12 m</td>
                    <td>5 m</td>
                    <td>1,4 m</td>
                  </tr>
                </tbody>
              </table>
              <p className={styles.infoText}>
                Chaque villa dispose d'une piscine privée. Nous proposons différents types de bassins :
                familial, sportif et décoratif. Ils varient en taille — le type de piscine dépend
                du nombre de chambres et de la superficie de la villa.
              </p>
            </div>
          </div>

          {/* Kitchen row */}
          <div className={`${styles.infoRow} ${styles.infoRowReverse}`}>
            <div className={styles.infoContent}>
              <h3 className={styles.infoFeatureTitle}>Cuisine Équipée</h3>
              <p className={styles.infoText}>
                Des cuisines spacieuses et lumineuses avec îlot central, espaces de repas pour les
                invités et la famille. Chaque cuisine est adaptée au style de la villa. La plupart
                de nos cuisines sont ouvertes sur le salon, mais nous proposons aussi des espaces
                fermés avec accès direct à la terrasse.
              </p>
            </div>
            <div className={styles.infoImageWrapper}>
              <img src={kitchenImage} alt="Cuisine de la villa" className={styles.infoImage} />
            </div>
          </div>
        </div>
      </section>

      <Footer />
    </div>
  );
};

export default LogementsPage;
